#include<bits/stdc++.h>
using namespace std;
const int N = 2.5e5+5;
struct days{
    long long a,b,id;
    bool operator > (const days &x)const{
        return b<x.b;
    }
}c[N];
long long n,f[N],ans,iv;
bool v[N];
priority_queue<days,vector<days>,greater<days> > q;
int main(){
    cin>>n;
    for(int i=1;i<=n;i++){cin>>c[i].a;c[i].id=i;}
    for(int i=1;i<=n;i++)cin>>c[i].b;
    for(int i=1;i<=n;i++){
        iv+=c[i].a;
        if(iv<c[i].b&&!q.empty()&&q.top().b>c[i].b){
            v[q.top().id]=0;
            iv+=q.top().b;
            q.pop();
            ans--;
        }
        if(iv>=c[i].b){
            ans++;
            iv-=c[i].b;
            q.push(c[i]);
            v[i]=1;
        }
    }
    cout<<ans<<endl;
    for(int i=1;i<=n;i++)
        if(v[i])cout<<i<<" ";
    return 0;
}
/*
第一，我学会了结构体重载运算符的方法。

第二，我学会了一种类似“替换”方式的贪心，
把代价太大的、前面干过的替换成代价更小的、更优的；
也像“反悔”，搞得定就不反悔，除非搞不定了。

第三，不开 long long 见祖宗，并且在定义 N 时一定一定记得 +5！
